  "cap_band_hot_title": "Faixa principal de bobina quente",
  "cap_band_hot_desc": "A janela de enrolamento a quente destacada cobre diâmetros de fio grandes de 14 mm a 50 mm para molas de serviço pesado usadas em equipamentos de energia, maquinaria pesada e aplicações exigentes de amortecimento.",
  "cap_band_test_value": "5-50 tonf",
  "cap_band_test_title": "Faixa de teste de carga pesada",
  "cap_band_test_desc": "Informações de patentes públicas indicam um grande dispositivo de teste de resistência e fadiga de mola de alta pressão projetado para validação de força de aproximadamente 5 a 50 toneladas.",
  "cap_band_standard_value": "GB / ISO / JIS",
  "cap_band_standard_title": "Cobertura de Padrões",
  "cap_band_standard_desc": "O site atual posiciona GB, ISO e JIS como padrões de referência primários em descrições de produtos e capacidades da empresa.",
  "cap_ref_title": "Links de referência pública",
  "cap_ref_desc": "Estas ligações apoiam as partes publicamente verificáveis da história da capacidade. As informações sobre aquisições e patentes vêm de páginas públicas de terceiros.",
  "cap_ref_xd_title": "Resultado de aquisição de mola XD e mola disco na China",
